var e=[{id:`L2_1`,type:`dialog`,speaker:`SOLOVEY_ADMIN_NULL_NULL`,text:{KOREA:`얼른 어머니만큼 성장해서 모두에게 도움이 되고 싶어요.`,JPN:`早くお母さんみたいに大きくなってみんなの助けになりたいです。`,ENG:`I want to grow up quickly, just like Mother, so I can be helpful to everyone.`,TWN:`我想快點長大變得跟媽媽一樣，能夠幫助所有人。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOLOVEY_ADMIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SOLOVEY_ADMIN_NULL_NULL`,text:{KOREA:`지금은 관리자 씨가 절 책임지고 있지만, 어른이 되면 제가 관리자 씨를 책임질 테니까요! 후후, 기대되죠?`,JPN:`今は管理者さんが私の面倒をみてくれていますが、大人になったら私が管理者さんの面倒をみてあげるんです！　ふふっ、楽しみでしょう？`,ENG:`Right now, Mr. Administrator is taking care of me. But when I grow up, I'll take care of you! Haha, it's something to look forward to, don't you think?`,TWN:`現在是管理者先生在照顧我，但等我長大後，我會照顧管理者先生的！呵呵，期待吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOLOVEY_ADMIN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};